	}
	if s, ok := authObj["token-field"].(string); ok {
		def.TokenField = s
	}
	if s, ok := authObj["header-name"].(string); ok {
		def.HeaderName = s
	}
	return def
}

// parseRequestShape converts a raw request config map (from engine.provider.request) into
