	}
	if q, ok := requestObj["query"].(map[string]any); ok {
		shape.Query = make(map[string]string, len(q))
		for k, v := range q {
			if vs, ok := v.(string); ok {
				shape.Query[k] = vs
			}
		}
	}
	if b, ok := requestObj["body-inject"].(map[string]any); ok {
		shape.BodyInject = make(map[string]string, len(b))
		for k, v := range b {
			if vs, ok := v.(string); ok {
