                  "type": "array",
                  "items": {
                    "type": "string"
                  },
                  "description": "List of additional repositories in format 'owner/repo' that pull requests can be created in. When specified, the agent can use a 'repo' field in the output to specify which repository to create the pull request in. The target repository (current or target-repo) is always implicitly allowed."
                },
                "github-token": {
                  "$ref": "#/$defs/github_token",
                  "description": "GitHub token to use for this specific output type. Overrides global github-token if specified."
                },
                "expires": {
                  "oneOf": [
                    {
                      "type": "integer",
                      "minimum": 1,
                      "description": "Number of days until expires"
                    },
                    {
                      "type": "string",
                      "pattern": "^[0-9]+[hHdDwWmMyY]$",
                      "description": "Relative time (e.g., '2h', '7d', '2w', '1m', '1y'); minimum 2h for hour values"
                    }
                  ],
                  "description": "Time until the pull request expires and should be automatically closed (only for same-repo PRs without target-repo). Supports integer (days) or relative time format. Minimum duration: 2 hours."
                },
                "auto-merge": {
                  "type": "boolean",
                  "description": "Enable auto-merge for the pull request. When enabled, the PR will be automatically merged once all required checks pass and required approvals are met. Defaults to false.",
                  "default": false
                },
                "base-branch": {
                  "type": "string",
                  "description": "Base branch for the pull request. Defaults to the workflow's branch (github.ref_name) if not specified. Useful for cross-repository PRs targeting non-default branches (e.g., 'vnext', 'release/v1.0')."
                },
                "footer": {
                  "type": "boolean",
                  "description": "Controls whether AI-generated footer is added to the pull request. When false, the visible footer content is omitted but XML markers (workflow-id, tracker-id, metadata) are still included for searchability. Defaults to true.",
                  "default": true
                },
                "fallback-as-issue": {
                  "type": "boolean",
                  "description": "Controls the fallback behavior when pull request creation fails. When true (default), an issue is created as a fallback with the patch content. When false, no issue is created and the workflow fails with an error. Setting to false also removes the issues:write permission requirement.",
                  "default": true
                },
                "auto-close-issue": {
                  "allOf": [
                    {
                      "$ref": "#/$defs/templatable_boolean"
                    }
                  ],
                  "description": "When true (default), automatically appends a closing keyword (\"Fixes #N\") to the PR description when the workflow is triggered from an issue and no closing keyword is already present. This causes GitHub to auto-close the triggering issue when the PR is merged. Set to false to prevent this behavior, e.g., for partial-work PRs or multi-PR workflows. Accepts a boolean or a GitHub Actions expression.",
                  "default": true
                },
                "github-token-for-extra-empty-commit": {
                  "type": "string",
                  "description": "Token used to push an empty commit after PR creation to trigger CI events. Works around the GITHUB_TOKEN limitation where pushes don't trigger workflow runs. Defaults to the magic secret GH_AW_CI_TRIGGER_TOKEN if set in the repository. Use a secret expression (e.g. '${{ secrets.CI_TOKEN }}') for a custom token, or 'app' for GitHub App auth."
                },
                "protected-files": {
                  "type": "string",
                  "enum": ["blocked", "allowed", "fallback-to-issue"],
                  "description": "Controls protected-file protection. blocked (default): hard-block any patch that modifies package manifests (e.g. package.json, go.mod), engine instruction files (e.g. AGENTS.md, CLAUDE.md) or .github/ files. allowed: allow all changes. fallback-to-issue: push the branch but create a review issue instead of a PR, so a human can review the manifest changes before merging.",
                  "default": "blocked"
                },
                "allowed-files": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  },
                  "description": "Exclusive allowlist of glob patterns. When set, every file in the patch must match at least one pattern \u2014 files outside the list are always refused, including normal source files. This is a restriction, not an exception: setting allowed-files: [\".github/workflows/*\"] blocks all other files. To allow multiple sets of files, list all patterns explicitly. Acts independently of the protected-files policy; both checks must pass. To modify a protected file, it must both match allowed-files and be permitted by protected-files (e.g. protected-files: allowed). Supports * (any characters except /) and ** (any characters including /)."
                },
                "preserve-branch-name": {
                  "type": "boolean",
                  "description": "When true, the random salt suffix is not appended to the agent-specified branch name. Invalid characters are still replaced for security, and casing is always preserved regardless of this setting. Useful when the target repository enforces branch naming conventions (e.g. Jira keys in uppercase such as 'bugfix/BR-329-red'). Defaults to false.",
                  "default": false
                },
                "excluded-files": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  },
                  "description": "List of glob patterns for files to exclude from the patch. Each pattern is passed to `git format-patch` as a `:(exclude)<pattern>` magic pathspec, so matching files are stripped by git at generation time and will not appear in the commit. Excluded files are also not subject to `allowed-files` or `protected-files` checks. Supports * (any characters except /) and ** (any characters including /)."
                },
                "patch-format": {
                  "type": "string",
                  "enum": ["am", "bundle"],
                  "default": "am",
                  "description": "Transport format for packaging changes. \"am\" (default) uses git format-patch/git am. \"bundle\" uses git bundle, which preserves merge commit topology, per-commit authorship, and merge-resolution-only content."
                },
                "staged": {
                  "type": "boolean",
                  "description": "If true, emit step summary messages instead of making GitHub API calls for this specific output type (preview mode)",
                  "examples": [true, false]
                }
              },
              "additionalProperties": false,
              "examples": [
                {
                  "title-prefix": "[docs] ",
                  "labels": ["documentation", "automation"],
                  "reviewers": "copilot",
                  "draft": false
                },
                {
                  "title-prefix": "[security-fix] ",
                  "labels": ["security", "automated-fix"],
                  "reviewers": "copilot"
                }
              ]
            },
