    "checkoutConfig": {
      "type": "object",
      "description": "Configuration for a single actions/checkout step",
      "additionalProperties": false,
      "properties": {
        "repository": {
          "type": "string",
          "description": "Repository to checkout in owner/repo format. Defaults to the current repository.",
          "examples": ["owner/repo", "github/gh-aw"]
        },
        "ref": {
          "type": "string",
          "description": "Branch, tag, or SHA to checkout. Defaults to the ref that triggered the workflow.",
          "examples": ["main", "v1.0.0", "feature/my-branch"]
        },
        "path": {
          "type": "string",
          "description": "Relative path within GITHUB_WORKSPACE to place the checkout. Defaults to the workspace root.",
          "examples": [".", "./libs/other-repo", "./workspace"]
        },
        "fetch-depth": {
          "type": "integer",
          "minimum": 0,
          "description": "Number of commits to fetch. 0 fetches all history. 1 (default) is a shallow clone. When multiple configs target the same path, the deepest value is used.",
          "examples": [0, 1, 10]
        },
        "sparse-checkout": {
          "type": "string",
          "description": "Enable sparse-checkout with newline-separated patterns. When multiple configs target the same path, patterns are merged.",
          "examples": [".github/\nsrc/", "docs/"]
        },
        "submodules": {
          "oneOf": [
            {
              "type": "string",
              "enum": ["recursive", "true", "false"]
            },
            {
              "type": "boolean"
            }
          ],
          "description": "Controls submodule checkout. Use \"recursive\" for all submodules, \"true\" for immediate submodules, or \"false\" to skip."
        },
        "lfs": {
          "type": "boolean",
          "description": "Whether to download Git LFS objects. Defaults to false."
        },
        "token": {
          "type": "string",
          "description": "Deprecated: Use github-token instead. GitHub token for authentication. Credentials are always removed after checkout (persist-credentials: false is enforced).",
          "examples": ["${{ secrets.MY_PAT }}", "${{ secrets.GITHUB_TOKEN }}"]
        },
        "github-token": {
          "type": "string",
          "description": "GitHub token for authentication. Use ${{ secrets.MY_TOKEN }} to reference a secret. Mutually exclusive with github-app (and deprecated app). Credentials are always removed after checkout (persist-credentials: false is enforced).",
          "examples": ["${{ secrets.MY_PAT }}", "${{ secrets.CROSS_REPO_PAT }}"]
        },
        "github-app": {
          "$ref": "#/$defs/github_app",
          "description": "GitHub App authentication. Mints a short-lived installation access token via actions/create-github-app-token. Mutually exclusive with github-token."
        },
        "current": {
          "type": "boolean",
          "description": "Marks this checkout as the logical current repository for the workflow. When set to true, the AI agent will treat this repository as its primary working target. Only one checkout may have current set to true. Useful for central-repo workflows targeting a different repository."
        },
        "fetch": {
          "oneOf": [
            {
              "type": "string",
              "description": "A single additional ref pattern to fetch after checkout."
            },
            {
              "type": "array",
              "description": "Additional Git refs to fetch after checkout. A git fetch step is emitted after the actions/checkout step.",
              "items": {
                "type": "string"
              }
            }
          ],
          "description": "Additional Git refs to fetch after the checkout. Supported values: \"*\" (all branches), \"refs/pulls/open/*\" (all open pull-request refs), branch names (e.g. \"main\"), or glob patterns (e.g. \"feature/*\").",
          "examples": [["*"], ["refs/pulls/open/*"], ["main", "feature/my-branch"], ["feature/*"]]
        }
      }
    },
