    "safe-outputs": {
      "type": "object",
      "$comment": "Required if workflow creates or modifies GitHub resources. Operations requiring safe-outputs: autofix-code-scanning-alert, add-comment, add-labels, add-reviewer, assign-milestone, assign-to-agent, assign-to-user, close-discussion, close-issue, close-pull-request, create-agent-session, create-agent-task (deprecated, use create-agent-session), create-code-scanning-alert, create-discussion, create-issue, create-project, create-project-status-update, create-pull-request, create-pull-request-review-comment, dispatch-workflow, hide-comment, link-sub-issue, mark-pull-request-as-ready-for-review, missing-data, missing-tool, noop, push-to-pull-request-branch, remove-labels, reply-to-pull-request-review-comment, resolve-pull-request-review-thread, set-issue-type, submit-pull-request-review, threat-detection, unassign-from-user, update-discussion, update-issue, update-project, update-pull-request, update-release, upload-asset. See documentation for complete details.",
      "description": "Safe output processing configuration that automatically creates GitHub issues, comments, and pull requests from AI workflow output without requiring write permissions in the main job",
      "examples": [
        {
          "create-issue": {
            "title-prefix": "[AI] ",
            "labels": ["automation", "ai-generated"]
          }
        },
        {
          "create-pull-request": {
            "title-prefix": "[Bot] ",
            "labels": ["bot"]
          }
        },
        {
          "add-comment": null,
          "create-issue": null
        }
      ],
      "properties": {
        "allowed-domains": {
          "type": "array",
          "description": "List of allowed domains for URL redaction in safe output handlers. Supports ecosystem identifiers (e.g., \"python\", \"node\", \"default-safe-outputs\") like network.allowed. These domains are unioned with the engine defaults and network.allowed when computing the final allowed domain set. localhost and github.com are always included.",
          "items": {
            "type": "string"
          }
        },
        "allowed-github-references": {
          "type": "array",
          "description": "List of allowed repositories for GitHub references (e.g., #123 or owner/repo#456). Use 'repo' to allow current repository. References to other repositories will be escaped with backticks. If not specified, all references are allowed.",
          "items": {
            "type": "string"
          },
          "examples": [["repo"], ["repo", "octocat/hello-world"], ["microsoft/vscode", "microsoft/typescript"], ["repo", "${{ github.repository }}"]]
        },
        "create-issue": {
          "oneOf": [
            {
              "type": "object",
              "description": "Configuration for automatically creating GitHub issues from AI workflow output. The main job does not need 'issues: write' permission.",
              "properties": {
                "title-prefix": {
                  "type": "string",
                  "description": "Optional prefix to add to the beginning of the issue title (e.g., '[ai] ' or '[analysis] ')"
                },
                "labels": {
                  "type": "array",
                  "description": "Optional list of labels to automatically attach to created issues (e.g., ['automation', 'ai-generated'])",
                  "items": {
                    "type": "string"
                  }
                },
                "allowed-labels": {
                  "type": "array",
                  "description": "Optional list of allowed labels that can be used when creating issues. If omitted, any labels are allowed (including creating new ones). When specified, the agent can only use labels from this list.",
                  "items": {
                    "type": "string"
                  }
                },
                "assignees": {
                  "oneOf": [
                    {
                      "type": "string",
                      "description": "Single GitHub username to assign the created issue to (e.g., 'user1' or 'copilot'). Use 'copilot' to assign to GitHub Copilot using the @copilot special value."
                    },
                    {
                      "type": "array",
                      "description": "List of GitHub usernames to assign the created issue to (e.g., ['user1', 'user2', 'copilot']). Use 'copilot' to assign to GitHub Copilot using the @copilot special value.",
                      "items": {
                        "type": "string"
                      }
                    }
                  ],
                  "description": "GitHub usernames to assign the created issue to. Can be a single username string or array of usernames. Use 'copilot' to assign to GitHub Copilot."
                },
                "max": {
                  "description": "Maximum number of issues to create (default: 1) Supports integer or GitHub Actions expression (e.g. '${{ inputs.max }}').",
                  "oneOf": [
                    {
                      "type": "integer",
                      "minimum": 1,
                      "maximum": 100
                    },
                    {
                      "type": "string",
                      "pattern": "^\\$\\{\\{.*\\}\\}$",
                      "description": "GitHub Actions expression that resolves to an integer at runtime"
                    }
                  ]
                },
                "target-repo": {
                  "type": "string",
                  "description": "Target repository in format 'owner/repo' for cross-repository issue creation. Takes precedence over trial target repo settings."
                },
                "allowed-repos": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  },
                  "description": "List of additional repositories in format 'owner/repo' that issues can be created in. When specified, the agent can use a 'repo' field in the output to specify which repository to create the issue in. The target repository (current or target-repo) is always implicitly allowed."
                },
                "expires": {
                  "oneOf": [
                    {
                      "type": "integer",
                      "minimum": 1,
                      "description": "Number of days until expires"
                    },
                    {
                      "type": "string",
                      "pattern": "^[0-9]+[hHdDwWmMyY]$",
                      "description": "Relative time (e.g., '2h', '7d', '2w', '1m', '1y'); minimum 2h for hour values"
                    },
                    {
                      "type": "boolean",
                      "enum": [false],
                      "description": "Set to false to explicitly disable expiration"
                    }
                  ],
                  "description": "Time until the issue expires and should be automatically closed. Supports integer (days), relative time format, or false to disable expiration. Minimum duration: 2 hours. When set, a maintenance workflow will be generated."
                },
                "group": {
                  "type": "boolean",
                  "description": "If true, group issues as sub-issues under a parent issue. The workflow ID is used as the group identifier. Parent issues are automatically created and managed, with a maximum of 64 sub-issues per parent.",
                  "default": false
                },
                "close-older-issues": {
                  "type": "boolean",
                  "description": "When true, automatically close older issues with the same workflow-id marker as 'not planned' with a comment linking to the new issue. Searches for issues containing the workflow-id marker in their body. Maximum 10 issues will be closed. Only runs if issue creation succeeds.",
                  "default": false
                },
                "close-older-key": {
                  "type": "string",
                  "description": "Optional explicit deduplication key for close-older matching. When set, a `<!-- gh-aw-close-key: <value> -->` marker is embedded in the issue body and used as the primary key for searching and filtering older issues instead of the workflow-id markers. This gives deterministic isolation across caller workflows and is stable across workflow renames. The value is normalized to identifier style (lowercase alphanumeric, dashes, underscores).",
                  "minLength": 1,
                  "pattern": "\\S"
                },
                "group-by-day": {
                  "type": "boolean",
                  "description": "When true, if an open issue with the same close-older-key (or workflow-id marker when no key is set) was already created today (UTC), post the new content as a comment on that existing issue instead of creating a new one. Groups multiple same-day runs into a single issue. Works best when combined with close-older-issues: true.",
                  "default": false
                },
                "footer": {
                  "type": "boolean",
                  "description": "Controls whether AI-generated footer is added to the issue. When false, the visible footer content is omitted but XML markers (workflow-id, tracker-id, metadata) are still included for searchability. Defaults to true.",
                  "default": true
                },
                "github-token": {
                  "$ref": "#/$defs/github_token",
                  "description": "GitHub token to use for this specific output type. Overrides global github-token if specified."
                },
                "staged": {
                  "type": "boolean",
                  "description": "If true, emit step summary messages instead of making GitHub API calls for this specific output type (preview mode)",
                  "examples": [true, false]
                }
              },
              "additionalProperties": false,
              "examples": [
                {
                  "title-prefix": "[ca] ",
                  "labels": ["automation", "dependencies"],
                  "assignees": "copilot"
                },
                {
                  "title-prefix": "[duplicate-code] ",
                  "labels": ["code-quality", "automated-analysis"],
                  "assignees": "copilot"
                },
                {
                  "allowed-repos": ["org/other-repo", "org/another-repo"],
                  "title-prefix": "[cross-repo] "
                },
                {
                  "title-prefix": "[weekly-report] ",
                  "labels": ["report", "automation"],
                  "close-older-issues": true
                }
              ]
            },
            {
              "type": "null",
              "description": "Enable issue creation with default configuration"
            }
          ],
          "description": "Enable AI agents to create GitHub issues from workflow output. Supports title prefixes, automatic labeling, assignees, and cross-repository creation. Does not require 'issues: write' permission."
        },
