    "stdio_mcp_tool": {
      "type": "object",
      "description": "Stdio MCP tool configuration",
      "properties": {
        "type": {
          "type": "string",
          "enum": ["stdio", "local"],
          "description": "MCP connection type for stdio (local is an alias for stdio)"
        },
        "registry": {
          "type": "string",
          "description": "URI to the installation location when MCP is installed from a registry",
          "examples": ["https://api.mcp.github.com/v0/servers/microsoft/markitdown"]
        },
        "command": {
          "type": "string",
          "minLength": 1,
          "$comment": "Mutually exclusive with 'container' - only one execution mode can be specified. Validated by 'not.allOf' constraint below.",
          "description": "Command for stdio MCP connections"
        },
        "container": {
          "type": "string",
          "pattern": "^[a-zA-Z0-9][a-zA-Z0-9/:_.-]*$",
          "$comment": "Mutually exclusive with 'command' - only one execution mode can be specified. Validated by 'not.allOf' constraint below.",
          "description": "Container image for stdio MCP connections"
        },
        "version": {
          "type": ["string", "number"],
          "description": "Optional version/tag for the container image (e.g., 'latest', 'v1.0.0', 20, 3.11). Numeric values are automatically converted to strings at runtime.",
          "examples": ["latest", "v1.0.0", 20, 3.11]
        },
        "args": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Arguments for command or container execution"
        },
        "entrypoint": {
          "type": "string",
          "description": "Optional entrypoint override for container (equivalent to docker run --entrypoint)",
          "examples": ["/bin/sh", "/custom/entrypoint.sh", "python"]
        },
        "entrypointArgs": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Arguments to add after the container image (container entrypoint arguments)"
        },
        "mounts": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[^:]+:[^:]+:(ro|rw)$"
          },
          "description": "Volume mounts for container in format 'source:dest:mode' where mode is 'ro' or 'rw'",
          "examples": [["/tmp/data:/data:ro"], ["/workspace:/workspace:rw", "/config:/config:ro"]]
        },
        "env": {
          "type": "object",
          "patternProperties": {
            "^[A-Z_][A-Z0-9_]*$": {
              "type": "string"
            }
          },
          "additionalProperties": false,
          "description": "Environment variables for MCP server"
        },
        "network": {
          "type": "object",
          "deprecated": true,
          "$comment": "DEPRECATED: Per-server network configuration is no longer supported. Use top-level workflow 'network:' configuration instead.",
          "properties": {
            "allowed": {
              "type": "array",
              "items": {
                "type": "string",
                "pattern": "^[a-zA-Z0-9]([a-zA-Z0-9\\-]{0,61}[a-zA-Z0-9])?(\\.[a-zA-Z0-9]([a-zA-Z0-9\\-]{0,61}[a-zA-Z0-9])?)*$",
                "description": "Allowed domain name"
              },
              "minItems": 1,
              "uniqueItems": true,
              "description": "List of allowed domain names for network access",
              "maxItems": 100
            },
            "proxy-args": {
              "type": "array",
              "items": {
                "type": "string"
              },
              "description": "Custom proxy arguments for container-based MCP servers"
            }
          },
          "additionalProperties": false,
          "description": "DEPRECATED: Per-server network configuration is no longer supported. Use top-level workflow 'network:' configuration instead. This field is ignored and will be removed in a future version."
        },
        "allowed": {
          "type": "array",
          "description": "List of allowed tool names for this MCP server",
          "items": {
            "type": "string"
          },
          "examples": [["*"], ["store_memory", "retrieve_memory"], ["brave_web_search"]]
        }
      },
      "additionalProperties": false,
      "$comment": "Validation constraints: (1) Mutual exclusion: 'command' and 'container' cannot both be specified. (2) Requirement: Either 'command' or 'container' must be provided (via 'anyOf'). (3) Type constraint: When 'type' is 'stdio' or 'local', either 'command' or 'container' is required. Note: Per-server 'network' field is deprecated and ignored.",
      "anyOf": [
        {
          "required": ["type"]
        },
        {
          "required": ["command"]
        },
        {
          "required": ["container"]
        }
      ],
      "not": {
        "allOf": [
          {
            "required": ["command"]
          },
          {
            "required": ["container"]
          }
        ]
      },
      "allOf": [
        {
          "if": {
            "properties": {
              "type": {
                "enum": ["stdio", "local"]
              }
            }
          },
          "then": {
            "anyOf": [
              {
                "required": ["command"]
              },
              {
                "required": ["container"]
              }
            ]
          }
        }
      ]
    },
    "http_mcp_tool": {
      "type": "object",
      "description": "HTTP MCP tool configuration",
      "properties": {
        "type": {
          "type": "string",
          "enum": ["http"],
