+// isRuntimeExpression reports whether value is exactly one GitHub Actions expression.
+func isRuntimeExpression(value string) bool {
+       trimmed := strings.TrimSpace(value)
+       return strings.HasPrefix(trimmed, "${{") && strings.HasSuffix(trimmed, "}}") && strings.TrimSpace(trimmed[3:len(trimmed)-2]) != ""
+}
+
+func parseEngineVersionValue(version any) (string, bool) {
+       versionStr := stringutil.ParseVersionValue(version)
+       if isRuntimeExpression(versionStr) {
+               return strings.TrimSpace(versionStr), true
+       }
+       return versionStr, false
+}
